    "one_click": {
      "label": "Hagaaji Helitaanka",
      "badge": "si toos ah oo dhammaystiran — hubi, hagaaji, xaqiiji, ku celi ilaa bartilmaameedka",
      "desc": "Hal gujis ayaa orkesteeya geeddi-socodka oo dhan gacan la'aan iyadoo la adeegsanayo dejinta caadiga ah; soo dejinta ayaa diyaar ah dhammaadka. Ma doorbidaysaa xakamaynta? Isticmaal \"Socodsii Hubinta\" hoose, dib u eeg natiijooyinka, ka dibna riix Hagaaji & Xaqiiji adiga laftaada."
    },
    "run_audit_label": "Socodsii Hubinta (tallaabada 1 ee 2)",
    "manual_path_explainer": "\"Socodsii Hubinta\" waxay qiimeysaa dukumentiga waxayna muujisaa waxa u baahan hagaajin — ka dibna waad dib u eegtaa oo waxaad riixdaa Hagaaji & Xaqiiji adiga laftaada (tallaabada 2). \"Hagaaji Helitaanka\" kor ku xusan waxay sameysaa labada tallaabo iyo dib-u-hubinta, si toos ah. \"Soo-saarista Qoraalka\" waxay kaliya soo saartaa qoraalka cayriin ah ee soo-saarista nuxurka.",
    "tagged_report": {
      "heading": "Warbixinta Tagged PDF",
      "close_aria": "Tuur warbixinta tagged-PDF",
      "note": "Bordhigan wuxuu sii joogi doonaa ilaa aad tuurto. Faahfaahinta isku midka ah waxay la socotaa soo dejinta A11y Report ee qaabka Adobe."
    },
    "docx_export": {
      "title": "U beddel nuxurka la hagaajiyay dukumenti Word leh qaababka cinwaanka dhabta ah, qoraal kale oo sawirrada ku saabsan, safafka madaxa miiska, qaab-dhismeedka liiska, iyo xiriiriyeyaal shaqeeya. Ku xaqiiji Hubiyaha Helitaanka ee Word ku dhex jira (Review → Check Accessibility) ka hor inta aanad qaybin."
    },
    "pptx_export": {
      "title": "Dib u dhis nuxurka la hagaajiyay oo ah deck PowerPoint leh cinwaanno slide dhab ah, qoraal kale oo sawirrada ku saabsan, safaf miis oo madax leh, liisas dhibco dhab ah, iyo amarka akhriska = amarka muuqaalka. Naqshad la heli karo oo dib loo dhisay — maahan nuqul muuqaal ah oo asalka ah. Ku xaqiiji Hubiyaha Helitaanka ee PowerPoint ka hor inta aanad qaybin."
    },
