      "1_1_16_or_1_0625": "1 1/16 (ama 1.0625)",
      "inch_rulers_use_binary_fractions_halve": "Mastarrada inch waxay isticmaalaan jajabyo binary ah: badhabo, rubuc, sideed-meelood, lix-iyo-toban-meelood.",
      "tape_measure_carpentry": "Cabbir shariidh ah (nijaarnimo)",
      "a_12_foot_tape_measure_has_marks_every": "Cabbir shariidh 12-cagood ah wuxuu leeyahay calaamado 1/16 inch kasta. Isticmaal caadi ah: akhri ilaa 1/8 ama 1/16 ugu dhow. Dheeman madow 19 3/16 inch kasta waxay calaamadeeyaan kala-fogaanta joist ee la naqshadeeyay.",
      "5_19_3_16_95_15_16_inches_8_feet": "5 × 19 3/16 = 95 15/16 inch ≈ 8 cagood",
      "each_16_inches_has_a_black_diamond_for": "16 inch kasta waxay leeyihiin dheeman madow oo kala-fogaanta stud caadiga ah.",
      "measuring_cups": "Koobabka cabbirka",
      "a_standard_set_includes_1_cup_1_2_1_3_": "Set caadi ah wuxuu ku jiraa 1 koob, 1/2, 1/3, 1/4. Setyada qaar waxay ku daraan 2/3 iyo 3/4. Koobabka cabbirka galaaska waxay leeyihiin calaamado 1/4, 1/3, 1/2, 2/3, 3/4 koob iyo 1 koob.",
      "1_4_1_2_3_4_use_both_or_three_1_4_cup_": "1/4 + 1/2 = 3/4 (isticmaal labada, AMA saddex 1/4 koob)",
