      "earth_hangs_in_a_fixed_spot_in_the_lun": "Dhulku wuxuu ka laadlaadaa meel go'an oo cirka dayaxa ah sababtoo ah Dayaxu wuxuu ku jiraa wareeg isku mid ah (waxaa xidhay xoogga mawjadda).",
      "begin_eva_on_the_lunar_surface": "Bilow EVA dusha dayaxa",
      "step_onto_the_moon_begin_eva": "👨‍🚀 Ku Tallaabo Dayaxa · Bilow EVA",
      "moonwalk_3d_mode_unresolved": "Habka 3D ee Socodka Dayaxa Lama Xallin",
      "webgl_failed_to_initialize_your_browse": "WebGL wuu ku guuldarraystay inuu bilaabmo. Browser-kaaga ama qalabkaaga ayaa laga yaabaa inaysan taageerin dardargelinta qalabka 3D.",
      "retry_3d_mode": "Dib u Isku Day Habka 3D",
      "interactive_3d_lunar_surface_eva_use_w": "EVA 3D is-dhexgal ah oo dusha dayaxa ah. Isticmaal WASD si aad u socoto, Space si aad u boodo cuf-isjiidadka lix-meelood-meel, F si aad u aruuriso muunadaha dhagaxa, iyo jiir si aad u eegto hareeraha. Aruuri muunadaha cilmiga dhulka oo sahmi dusha Dayaxa agagaarka qaybta dayaxa.",
      "alsep_science_station": "Saldhigga Sayniska ALSEP",
      "the_apollo_lunar_surface_experiments_p": "Apollo Lunar Surface Experiments Package (ALSEP) wuxuu shaqeeyay sannado ka dib markii cirbixiyeennadu ay tageen. Cabbiraha dhulgariirka wuxuu ogaaday gariirrada dayaxa iyo saamaynta meteorite ilaa 1977.",
      "lunar_rover_lrv": "Gaadhiga Dayaxa (LRV)",
      "the_lunar_roving_vehicle_cost_38_milli": "Lunar Roving Vehicle wuxuu ku kacay dollar milyan 38. Gaadhiga Apollo 17 wuxuu safray km 35.7 — wali waxaa lagu dhigay Dayaxa furayaal!",
      "american_flag": "Calanka Mareykanka",
      "the_flags_on_the_moon_have_been_bleach": "Calammada Dayaxa ku yaal waxay u beddelmeen caddaan saafi ah sababtoo ah tobannaan sano oo shucaac UV ah oo aan la sifayn. Calanka Apollo 12 oo keliya ayaa qiiqa matoorka dhulqaaday.",
      "seismometer": "Cabbiraha Dhulgariirka",
      "lunar_seismometers_detected_deep_moonq": "Cabbirayaasha dhulgariirka dayaxa waxay ogaadeen gariirro dayax oo qoto dheer oo ay sababeen xoogagga mawjadaha Dhulka qoto dheer km 700-1100. Dayaxu wali wuxuu leeyahay xudun qayb ahaan dhalaashay!",
      "laser_retroreflector": "Laser Retroreflector",
      "scientists_bounce_lasers_off_this_mirr": "Saynisyahannadu waxay laser ka soo celiyaan muraayaddan si ay u cabbiraan masaafada Dhulka-Dayaxa oo saxnaan cm 1 ah. Dayaxu wuxuu ka fogaadaa cm 3.8 Dhulka sannad kasta.",
      "moonwalk_eva_3": "👨‍🚀 Socodka Dayaxa (EVA)",
      "explore_collect_samples_jump_in_1_6_gr": "Sahmi • Aruuri muunadaha • Bood cuf-isjiidadka 1/6!",
      "end_eva_return_to_lm": "⬆️ Dhammee EVA — Ku noqo LM",
      "animated_lunar_ascent_sequence_ascent_": "Isku-xigxiga kor u kaca dayaxa ee dhaqdhaqaaqa leh. Marxaladda kor u kaca waxay ka bilaabataa Dayaxa iyadoo ka tagaysa marxaladda soo degitaanka gadaal, waxay kor u baxaysaa wareegga dayaxa in ka badan kiilomitir 60, ka dibna waxay samaynaysaa kulan-isku-xidhid qaybta amarka Columbia ee wareegaysa. HUD wuxuu muujiyaa dhererka, marxaladda, iyo masaafada ilaa CSM.",
      "lunar_ascent_rendezvous": "Kor u kaca Dayaxa iyo Kulanka",
      "ascent_stage_launches_from_moon_docks_": "Marxaladda kor u kaca waxay ka bilaabataa Dayaxa waxayna isku xidhataa Columbia",
      "the_lm_s_ascent_engine_a_single_start_": "Matoorka kor u kaca ee LM — matoor hypergolic hal-bilow ah oo aan lahayn ikhtiyaar joojin — wuxuu shidan yahay si uu kaaga bilaabo dusha dayaxa. Marxaladda soo degitaanka waxay u shaqaysaa sidii furaha bilaabidda waxayna ka hadhaa gadaal. Waad la kulantaa oo isku xidhataa Columbia, ka dibna waxaad tuurtaa «Eagle» (kaas oo ugu dambeyntii ku dhaca Dayaxa).",
