      "friction_slows_wind_near_surface": "khilaafku wuxuu gaabiyaa dabaysha meel u dhow dusha",
      "add_a_bird_to_ride_the_wind_currents": "Ku dar shimbir si uu ugu fuulo qulqulka dabaysha",
      "add_bird": "🐦 Ku Dar Shimbir",
