      "scaphoid_bone": "Lafta Scaphoid",
      "600_muscles_movement_posture_heat_prod": "Muruqyo 600+ — dhaqdhaqaaq, istaag, samaynta kulaylka, xasilinta xubnaha isku-xirka.",
      "rotator_cuff_sits": "Rotator Cuff (SITS)",
      "iliopsoas": "Iliopsoas",
