      "follow_a_red_blood_cell_through_the_en": "Raac unug dhiig cas ah dhammaan nidaamka wareegga dhiigga.",
      "right_atrium": "Atrium Midig",
      "deoxygenated_blood_from_the_body_enter": "Dhiigga aan lahayn oksijiin ee ka yimaada jirku wuxuu galaa atrium midig isagoo maraya vena cava sare iyo hoose.",
      "right_ventricle": "Ventricle Midig",
      "blood_passes_through_the_tricuspid_val": "Dhiigga wuxuu maraa valve-ka tricuspid isagoo galaya ventricle midig, kaas oo u tuujiya sambabbada.",
      "the_right_ventricle_ejects_blood_throu": "Ventricle midig wuxuu tuuraa dhiigga isagoo maraya valve-ka pulmonary galaya halbowlaha pulmonary ee labada sambab.",
      "lung_capillaries": "Capillaries-ka Sambabada",
      "in_the_alveolar_capillaries_co2_is_rel": "Capillaries-ka alveoli, CO2 waa la sii daayaa O2 waana la qaataa iyada oo loo maro xuubka alveoli khafiifka ah.",
      "pulmonary_veins": "Xididada Pulmonary",
      "freshly_oxygenated_blood_returns_to_th": "Dhiigga cusub ee oksijiin helay wuxuu ku noqdaa wadnaha isagoo maraya afarta xidid ee pulmonary.",
      "left_atrium": "Atrium Bidix",
      "the_four_pulmonary_veins_empty_oxygena": "Afarta xidid pulmonary waxay ku shubaan dhiigga oksijiin leh atrium bidix, kaas oo buuxsama kadibna u riixa isagoo maraya valve-ka mitral.",
      "left_ventricle": "Ventricle Bidix",
      "blood_passes_through_the_mitral_valve_": "Dhiigga wuxuu maraa valve-ka mitral isagoo galaya ventricle bidix ee muruqa leh, qolka ugu xoog badan wadnaha.",
      "the_left_ventricle_powerfully_ejects_b": "Ventricle bidix wuxuu si xoog leh u tuuraa dhiigga isagoo maraya valve-ka aorta galaya aorta, waddada weyn ee jirka.",
      "body_tissues": "Unugyada Jirka",
      "arteries_branch_into_arterioles_and_ca": "Halbowlayaashu waxay u kala baxaan arterioles iyo capillaries halkaas oo la gaarsiiyo O2 iyo nafaqooyin lana ururiyo CO2/qashin.",
      "venous_return": "Soo-celinta Xididka",
      "deoxygenated_blood_returns_through_ven": "Dhiigga aan lahayn oksijiin wuxuu ku soo noqdaa venules iyo xididada, isagoo la kaashanaya boombooyinka muruqa iyo valfyada, ilaa atrium midig.",
      "path_of_air": "Waddada Hawada",
      "trace_the_journey_of_a_breath_of_air_f": "Raac safarka neefta hawada laga bilaabo sanka ilaa alveoli iyo dib u soo noqoshada.",
      "nasal_cavity_2": "Godka Sanka",
      "air_enters_through_the_nostrils_and_is": "Hawadu waxay gashaa dulal sanka waana la kululeeyaa, la qoyaa, waana la sifeeyaa iyada oo loo maro xuubabka xabka iyo turbinates.",
      "pharynx_2": "Cunaha",
      "air_passes_through_the_nasopharynx_and": "Hawadu waxay martaa nasopharynx iyo oropharynx, waddo lala wadaago mareenka cuntada.",
      "larynx": "Larynx",
      "air_crosses_the_vocal_cords_in_the_voi": "Hawadu waxay gudubtaa xadhkaha codka ee sanduuqa codka. Epiglottis wuxuu ka ilaaliyaa cuntada inay gasho waddada hawada.",
      "trachea_2": "Duunta Hawada",
      "the_trachea_windpipe_is_reinforced_by_": "Duunta hawadu waxaa xoojiya wareegyada cartilage ee qaabka C leh. Cilia waxay kor u dhaqaajiyaan xabka si ay u qabtaan wasakhda.",
      "bronchi": "Bronchi",
      "the_trachea_splits_into_left_and_right": "Duunta hawadu waxay u kala baxdaa bronchi weyn bidix iyo midig, mid kastaa wuxuu galaa hal sambab. Waxay u kala baxaan bronchioles yaryar.",
      "alveoli_2": "Alveoli",
      "300_million_grape_like_sacs_where_gas_": "Kiishash 300 milyan oo canab u eg halkaas oo isweydaarsiga gaasku dhaco. O2 wuxuu ku faafaa dhiigga; CO2 wuxuu u faafaa dibedda. Bedka dusha wuxuu la mid yahay garoon tennis.",
      "exhalation": "Neef-saaris",
      "the_diaphragm_relaxes_and_rises_reduci": "Diaphragm wuu debcaa oo kor u kacaa, isagoo yaraynaya mugga sambabada. Hawada CO2 badan waxaa dibedda loo riixaa iyada oo la maraya waddo la mid ah oo dib u socota.",
      "path_of_food": "Waddada Cuntada",
      "follow_a_meal_from_mouth_through_the_e": "Raac cunto laga bilaabo afka dhammaan nidaamka dheefshiidka.",
      "mouth": "Af",
      "teeth_mechanically_break_food_down_sal": "Ilkuhu waxay si makaanik ah u jajabiyaan cuntada. Amylase candhuufta ayaa bilaaba dheefshiidka istaarijka. Carrabku wuxuu cuntada u sameeyaa bolus.",
      "pharynx_esophagus": "Cunaha & Esophagus",
      "swallowing_pushes_the_bolus_past_the_e": "Liqiddu waxay bolus u riixaan epiglottis. Mowjadaha peristaltic waxay hoos ugu dhaqaajiyaan esophagus 25cm ah qiyaastii 8 ilbiriqsi.",
      "gastric_acid_ph_1_5_3_5_and_pepsin_bre": "Aashitada caloosha (pH 1.5-3.5) iyo pepsin waxay jajabiyaan borotiinnada. Wareejinta waxay soo saartaa chyme 2-4 saacadood.",
      "duodenum": "Duodenum",
      "the_first_25cm_of_the_small_intestine_": "Kan 25cm ee ugu horreeya xiidmaha yaryar wuxuu ka helaa xameeti beerka/kiishka xameetida iyo enzymes-ka pancreas.",
      "jejunum_ileum": "Jejunum & Ileum",
      "most_nutrient_absorption_occurs_here_v": "Nuugista nafaqada intooda badan halkan ayay ka dhacdaa iyada oo loo maro villi iyo microvilli, kordhinaya bedka dusha 600 jeer. Dhererka 6-7 mitir.",
      "water_and_electrolytes_are_reabsorbed_": "Biyaha iyo electrolytes waa dib loo nuugaa. Bakteeriyada xiidmaha waxay khamiiriyaan fiber-ka hadhay, iyagoo soo saaraya fitamiinnada K iyo B12.",
      "rectum_excretion": "Rectum & Saaris",
      "waste_is_compacted_and_stored_in_the_r": "Qashinka waa la cadaadiyaa waana lagu kaydiyaa rectum ilaa saxarada. Safarka oo dhan wuxuu qaataa 24-72 saacadood.",
      "path_of_a_nerve_signal": "Waddada Calaamadda Dareemaha",
      "trace_a_reflex_arc_from_stimulus_to_re": "Raac qaanso reflex ah laga bilaabo kicinta ilaa jawaabta.",
      "receptor": "Qaataha",
      "a_sensory_receptor_in_the_skin_detects": "Qaataha dareenka ee maqaarka (sida taabashada dusha kulul) wuxuu ogaadaa kicinta xanuunka wuxuuna soo saaraa calaamad koronto.",
      "sensory_neuron": "Dareemaha Dareenka",
      "the_signal_travels_along_a_sensory_aff": "Calaamaddu waxay ku socotaa dareemaha dareenka (afferent) ilaa laf-dhabarka xawaare gaaraya 120 m/s iyada oo loo maro gudbinta saltatory.",
      "in_the_dorsal_horn_the_sensory_neuron_": "Geeska dhabarka, dareemaha dareenku wuxuu synapse la sameeyaa interneuron. Reflexes, calaamaddu uma baahna inay gaarto maskaxda.",
      "interneuron": "Interneuron",
      "the_interneuron_in_the_spinal_gray_mat": "Interneuron-ka maaddada cawlan ee laf-dhabarka wuxuu isku daraa calaamadda wuxuuna u gudbiyaa dareemaha dhaqdhaqaaqa.",
      "motor_neuron": "Dareemaha Dhaqdhaqaaqa",
      "the_motor_efferent_neuron_carries_the_": "Dareemaha dhaqdhaqaaqa (efferent) wuxuu qaadaa calaamadda amarka geeska hore ilaa muruqa la bartilmaameedsaday.",
      "effector_muscle": "Fuliye (Muruq)",
