      "print_tissue_with_living_cells_scaffol": "Print tissue living cell + scaffold. Maqaar, cartilage, kelli. Xubno buuxa weli fog.",
      "engineer_biological_systems_bacteria_t": "Farsame biological system. Bakteeriya soo saara dawo, yeast soo saara opioid, algal biofuel.",
      "bt_corn_insect_resistance_roundup_read": "Bt corn (insect resistance), Roundup Ready (herbicide), Golden Rice (vitamin A).",
      "str_profiling_mtdna_degraded_samples_y": "STR profiling, mtDNA (sample xumaaday), Y chromosome (khadka aabbaha). Isbarbardhig database.",
      "snp_arrays_23andme_ancestrydna_reveals": "SNP array (23andMe, AncestryDNA). Waxay muujiyaan biogeographic ancestry + qaraabo DNA.",
      "detect_cancer_dna_in_blood_earlier_dia": "Detect cancer DNA dhiigga. Ogaansho hore, treatment monitoring.",
      "treat_solid_tumors_til_therapy_iovance": "Daawee solid tumor. TIL therapy (Iovance, melanoma) FDA-approved 2024.",
      "engineered_microbes_clean_up_oil_spill": "Microbe la farsameeyay waxay nadiifiyaan daadinta saliidda, wasakhda caagga, biraha culus.",
      "pcr_polymerase_chain_reaction_2": "🧪 PCR (polymerase chain reaction)",
      "amplifies_specific_dna_sequences_a_bil": "Wuxuu kordhiyaa DNA sequence gaar ah bilyan jeer. workhorse ee molecular biology, diagnostics, forensics.",
      "the_3_steps_repeated_30": "Tallaabooyinkan 3 (~30× la celceliyay)",
