      "quantity_with_both_magnitude_and_direc": "Tiro leh xoog IYO jiho labadaba. Waxaa loo sawiraa fallaadh. Tusaale: xawlaha, xoogga, barakac.",
      "scalar_just_a_number_mass_temperature_": "Scalar = tiro keliya (mad, heerkul, waqti). Vector = xoog + jiho.",
      "place_tail_of_second_at_head_of_first_": "Dhig dabada kan labaad madaxa kan hore. Natiijadu = dabada kan hore ilaa madaxa kan labaad.",
      "place_tails_together_diagonal_of_paral": "Isku dhig dabooyinka. Xarriiqda toosan ee mustatiilka barbar-siman = natiijada.",
      "vector_v_at_angle_v_v_cos_v_y_v_sin": "Vector v xagalka θ: vₓ = v·cos θ, v_y = v·sin θ.",
      "v_v_v_y_v_z_pythagoras_in_any_dimensio": "|v| = √(vₓ² + v_y² + v_z²). Fiisagoras cabbir kasta.",
      "magnitude_1_v_v_v_often_called_the_dir": "Xoog 1. v̂ = v / |v|. Inta badan waxaa loo yaqaan \"jihada\" v.",
      "a_b_a_b_cos_gives_scalar_zero_when_per": "a·b = |a||b|cos θ. Waxay bixisaa scalar. Eber marka ay qummanaan yihiin. Taban marka xagalku > 90°.",
      "a_b_a_b_sin_n_gives_vector_perpendicul": "a×b = |a||b|sin θ · n̂. Waxay bixisaa vector QUMMAN labadooda. Xoog = aagga mustatiilka barbar-siman.",
      "curl_fingers_from_a_to_b_thumb_points_": "Farihiisa ka duub a ilaa b. Suulku wuxuu tilmaamayaa jihada a×b. (Iskuduwayaal gacan-midig.)",
      "c_a_c_b_generates_a_plane_or_line_of_v": "c₁·a + c₂·b. Waxay abuurtaa diyaarad (ama xariiq) faktoyaal ah.",
      "newton_s_2nd_law_f_ma_net_force_is_vec": "Sharciga 2aad ee Newton: F = ma. Xoogga guud waa wadarta vector ee dhammaan xoogagga.",
      "airplane_heading_wind_vector_ground_ve": "Jihada diyaaradda + vectorka dabaysha → xawaaraha dhulka (wadarta vector).",
