      "regular_tessellations_3_only": "Turxaamin caadi ah (3 kaliya)",
      "equilateral_triangle_square_regular_he": "Saddex-gees dhinac-siman, afargees, lix-gees caadi ah. Kaliya badan-geesyada caadiga ah ee dul-daboola diyaaradda.",
      "why_only_3": "Maxay saddex kaliya?",
      "interior_angle_must_divide_360_triangl": "Xagalka gudaha waa inuu qaybiyaa 360°. Saddex-gees 60° (×6), afargees 90° (×4), lix-gees 120° (×3). Shan-geeska 108° ma qaybsho 360° → keligiis ma turxaamin karo.",
      "semiregular_archimedean_tessellations": "Turxaamin nus-caadi ah (Archimedean)",
      "8_in_total_combine_multiple_regular_po": "8 guud ahaan. Isku dar badan-geesyo caadi ah oo badan; habraac isku mid ah dhundhun kasta.",
      "penrose_tilings_1974": "Turxaanka Penrose (1974)",
      "aperiodic_tiling_never_repeats_exactly": "Turxaan aan-xilliyeed — waligiis si sax ah kuma soo noqdo. Simmaan 5-jibbaaran. Waxay dhiirrigelisay helitaanka quasicrystals.",
      "honeycomb_conjecture": "Malaha shinnida (honeycomb)",
      "hexagonal_tiling_minimizes_total_perim": "Turxaanka lix-geesku wuxuu yareeyaa wareega guud ee aag la siiyay. Waxaa cadeeyay Hales (1999). Sababta shinnidu u isticmaasho lix-geesyada.",
      "voronoi_diagrams": "Jaantusyada Voronoi",
      "each_region_points_closest_to_one_seed": "Gobol kastaa = dhibcaha ugu dhow hal barta \"abuur\" ah. Waxay ka soo muuqataa dabeecadda (dhibcaha geriga, dildilaaca dhoobada, habaynta unugyada).",
      "hyperbolic_tilings": "Turxaanka hyperbolik",
      "on_a_hyperbolic_plane_regular_pentagon": "Diyaarad hyperbolik ah, shan-geesyada caadiga ah (iyo qaabab kale oo badan) WAY turxaamin karaan. Taxanaha M.C. Escher ee \"Circle Limit\".",
      "wang_tiles_1961": "Turxaanka Wang (1961)",
      "colored_squares_that_must_match_neighb": "Afargeesyo midab leh oo ay tahay inay u-dhigmaan deriska geesaha. Waxay ku dayan karaan mishiinka Turing → dhibaatada turxaanku guud ahaan lama go'aamin karo.",
      "einstein_tile_2023": "Turxaanka \"Einstein\" (2023)",
      "a_single_tile_that_aperiodically_tiles": "Hal turxaan oo si aan-xilliyeed ah u turxaamiya diyaaradda (qaababka \"hat\" iyo \"spectre\"). Helitaan muhiim ah oo dhawaan la sameeyay.",
      "a_b_pythagorean_theorem": "a²+b² Aragtida Fiisagoras",
      "in_a_right_triangle_a_b_c_where_c_is_t": "Saddex-gees qumman, a² + b² = c² halka c uu yahay hypotenuse-ka. Kooxaha tirooyinka (a, b, c) ee tan buuxiya waxaa loo yaqaan saddex-guud Pythagorean. Saddex-guud \"aasaasi\" ma laha wax wadaag ah.",
      "generating_primitive_triples": "Abuurista saddex-guudka aasaasiga ah: ",
      "for_positive_integers_m_n_with_no_comm": "Tirooyin togan m > n oo aan wax wadaag lahayn oo aan labaduba kelin ahayn, a = m² − n², b = 2mn, c = m² + n². Isku day m=2, n=1 → (3,4,5).",
      "triangle_types_and_formulas": "△ Noocyada saddex-geeska iyo qaacidooyinka",
