      "why_only_5": "Maxay shan kaliya?",
      "at_each_vertex_you_need_3_polygons_who": "Dhundhun kasta, waxaad u baahan tahay 3+ badan-gees oo wadarta xagalkoodu ka yar tahay 360° (haddii kale siman ama aan suurtogal ahayn). Kaliya 5 isku-dar ayaa u shaqeeya badan-geesyada caadiga ah.",
      "euler_s_formula": "Qaacidada Euler",
      "v_e_f_2_holds_for_every_convex_polyhed": "V − E + F = 2 waxay u shaqaysaa badan-wejiile godan kasta (oo ay ku jiraan dhammaan 5-da adke Platonic).",
      "duality": "Laba-jibbaarnimo",
      "connecting_face_centers_of_a_platonic_": "Isku xirka bartamayaasha wejiyada adke Platonic wuxuu bixiyaa \"laba-jibbaarkiisa\". Kuyub ↔ octahedron; dodecahedron ↔ icosahedron; tetrahedron ↔ isaga qudhiisa.",
      "archimedean_solids": "Adkeyaasha Archimedean",
      "13_semi_regular_solids_same_arrangemen": "13 adke nus-caadi ah — habraac isku mid ah dhundhun kasta, laakiin noocyo badan-gees oo badan. Waxaa ku jira icosahedron la gooyay (qaabka kubbadda cagta).",
      "kepler_poinsot_polyhedra": "Badan-wejiilaha Kepler-Poinsot",
      "4_regular_star_polyhedra_with_pentagra": "4 badan-wejiile xiddig-nooc caadi ah oo leh wejiyo ama dhundhummo pentagram ah. Aan-godnayn.",
      "koch_snowflake": "Baraf-dhalaalka Koch",
      "start_with_triangle_on_each_side_repla": "Ku bilow saddex-gees. Dhinac kasta, ku beddel saddexdiisa dhexe laba dhinac oo saddex-gees ka yar. Ku celi. Wareeg aan dhammaad lahayn, aag xaddidan.",
      "sierpinski_triangle": "Saddex-geeska Sierpinski",
      "start_with_triangle_remove_middle_smal": "Ku bilow saddex-gees. Ka saar saddex-geeska dhexe (ka yar). Ku celi saddex-gees kasta oo hadhay. Cabbirka Hausdorff log(3)/log(2) ≈ 1.585.",
      "cantor_set": "Kooxda Cantor",
      "remove_middle_third_of_segment_repeat_": "Ka saar saddex-meelood-dhexe qaybta. Ku celi qayb kasta oo hadhay. Aan-la-tirin-karin oo aan dhammaad lahayn laakiin dhererka guud waa eber.",
      "mandelbrot_set": "Kooxda Mandelbrot",
      "points_c_where_iterating_z_z_c_stays_b": "Dhibcaha c halka ku-celinta z = z² + c ay xaddidan tahay. Faahfaahin aan dhammaad lahayn heer kasta oo weynayn. Waxaa la helay 1980.",
      "julia_set": "Kooxda Julia",
      "for_each_c_points_z_where_iterating_z_": "c kasta, dhibcaha z halka ku-celinta z = z² + c ay xaddidan tahay. c kastaa wuxuu bixiyaa kooxda Julia oo kala duwan; wadajir waxay turxaamiyaan kooxda Mandelbrot.",
      "dragon_curve": "Qalooca masduulaaga",
      "fold_a_strip_of_paper_in_half_repeated": "Laallaabi jeeska warqad si isdaba joog ah; laab kasta ka kala fur 90°. Ama beddelaad soo noqnoqda oo qaybaha.",
      "barnsley_fern": "Fern-ka Barnsley",
      "iterated_function_system_random_select": "Nidaam hawl-celis ah. Doorasho kala sooc la'aan ah oo 4 maab affine ah waxay soo saartaa qaab fern.",
      "hausdorff_dimension": "Cabbirka Hausdorff",
      "fractional_dimension_coastline_1_2_1_3": "Cabbir jajab ah. Xeebtu ~1.2-1.3 iyadoo ku xiran dalka. Waxay qabtaa \"qallafsanaanta\" ka baxsan cabbirrada tirada dhan.",
      "defining_property_strict_self_similari": "Sifo qeexaya. Is-ekaansho adag (Koch) ama tirakoob (xeebo).",
      "real_world_fractals": "Fraktalka dunida dhabta ah",
      "coastlines_trees_lungs_bronchi_blood_v": "Xeebo, geedo, sambabbo (bronchi), xididdada dhiigga, shabakadaha wabiyada, silsiladaha buuraha, daruuraha, hillaac.",
      "flat_plane_parallel_postulate_holds_an": "Diyaarad siman. Mabda'a xariiqyada barbar-simani wuu shaqeeyaa. Xaglaha saddex-geesku waxay isku darsamaan si sax ah 180°.",
      "surface_of_sphere_triangle_angles_sum_": "Dusha kuraydhka. Xaglaha saddex-geesku waxay isku darsamaan IN KA BADAN 180°. Xad-dhaafku wuxuu la barbar socdaa aagga. Waxaa loo isticmaalaa marin-habaynta.",
      "saddle_shaped_surface_triangle_angles_": "Dusha qaab-kore ah. Xaglaha saddex-geesku waxay isku darsamaan IN KA YAR 180°. Barbar-siman badan ayaa maraya bar aan xariiq ku jirin.",
      "shortest_paths_on_a_surface_straight_l": "Jidadka ugu gaaban ee dusha. Xariiqyo toosan (Euclidean); goobooyin waaweyn (kuraydh); xariiqyo hyperbolik.",
      "largest_circles_on_a_sphere_equator_me": "Goobooyinka ugu waaweyn ee kuraydhka. Dhulbaraha + goobaha. Duulimaadyada diyaaraduhu waxay raacaan jidadka goobada-weyn.",
      "euclidean_0_spherical_positive_hyperbo": "Euclidean = 0. Kuraydhle = togan. Hyperbolik = taban. Qalooca ayaa go'aamiya joomatariga.",
      "on_sphere_of_radius_r_triangle_area_r_": "Kuraydh nuscabbirkiisu R yahay, aagga saddex-geeska = R² × (wadarta xagalka − π).",
      "positions_on_earth_s_surface_use_spher": "Meelaha dusha Dhulka waxay isticmaalaan joomatari kuraydhle (ama si sax ah, ellipsoidal).",
      "nyc_to_tokyo_is_shortest_via_the_arcti": "NYC ilaa Tokyo waxay ugu gaaban tahay Arctic-ga, maaha si toos ah bari — taasi waa goobada-weyn.",
      "spacetime_is_curved_by_mass_energy_geo": "Waqti-bannaanka waxaa qalloociya cuf-tamar. Geodesics-ka maraya waqti-bannaan qalloocan AYAA ah jidadka shayada si xor ah u dhacaya.",
      "mercator": "Mercator",
      "robinson": "Robinson",
      "winkel_tripel": "Winkel tripel",
